import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * DUES - a REDEFINES program, translated from COBOL 85. Defect variant:
 * the wrong-scale reinterpretation. This translation misreads the
 * REDEFINES view as if it had the same implied scale as its target, using
 * the raw cents value directly as dollars (no decimal shift). Every dues
 * value comes out 100x too large - the fee and tier are both wrong.
 */
public final class Dues {

    private static final BigDecimal RATE = new BigDecimal("5");
    private static final BigDecimal HUNDRED = new BigDecimal("100");
    private static final BigDecimal THRESHOLD = new BigDecimal("100");
    private static final BigDecimal PIC_9_4_V99 = new BigDecimal("10000");
    private static final BigDecimal PIC_9_6 = new BigDecimal("1000000");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        BigDecimal cents = numval(in.readLine());
        // BUG: the REDEFINES view reinterprets the digits at scale 2; this
        // drops the implied decimal and uses the cents value as dollars.
        BigDecimal dollars = cents;

        BigDecimal fee = dollars.multiply(RATE).divide(HUNDRED).setScale(2, RoundingMode.HALF_UP).remainder(PIC_9_4_V99);
        String tier = dollars.compareTo(THRESHOLD) > 0 ? "HIGH" : "LOW ";

        StringBuilder out = new StringBuilder();
        out.append("DOLLARS=").append(dollars.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("FEE=").append(fee.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("TIER=").append(tier).append('\n');
        System.out.print(out);
    }

    private static BigDecimal numval(String s) {
        try {
            return new BigDecimal(s.trim()).setScale(0, RoundingMode.DOWN).remainder(PIC_9_6);
        } catch (NumberFormatException e) {
            System.err.println("DUES: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO;
        }
    }
}
